def get_text(h):
    # prefer Matn if exists and non-empty; else hadithTxt
    t = h.get('Matn') or ''
    if t and t.strip():
        return t
    return h.get('hadithTxt') or ''
# Search hadiths containing certain keyword normalized
def search_keyword(keyword_norm):
    res = []
    for h in hadith:
        t = get_text(h)
        if not t:
            continue
        if keyword_norm in normalize_ar(t):
            res.append(h)
    return res

len(search_keyword('لولا')), len(search_keyword('الاذى')), len(search_keyword('نساء')), len(search_keyword('بالاذى'))

def search_with_terms(terms):
    res=[]
    for h in hadith:
        t = get_text(h)
        if not t:
            continue
        norm = normalize_ar(t)
        ok=True
        for term in terms:
            if term not in norm:
                ok=False
                break
        if ok:
            res.append(h)
    return res

hits = search_with_terms(['لولا','الاذي'])
